#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[1001];
        scanf("%s", s);
        int max = 0;
        for (int i = 0; i < strlen(s); i++) {
            for (int j = i + 1; j <= strlen(s); j++) {
                char sub[j - i + 1];
                strncpy(sub, s + i, j - i);
                sub[j - i] = '\0';
                for (int k = 0; k < j - i; k++) {
                    if (isalpha(sub[k])) {
                        for (int digit = 0; digit <= 9; digit++) {
                            char temp = sub[k];
                            sub[k] = digit + '0';
                            int num = atoi(sub);
                            if (num > max) max = num;
                            sub[k] = temp;
                        }
                    }
                }
                int num = atoi(sub);
                if (num > max) max = num;
            }
        }
        printf("%d\n", max);
    }
    return 0;
}

